import React from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

// เพิ่ม CSS นี้ในไฟล์ App.css หรือสร้างไฟล์ CSS ใหม่
// .lantern-animation-1 {
//   animation: moveLeftRight 2s infinite ease-in-out;
// }
// .lantern-animation-2 {
//   animation: moveRightLeft 2s infinite ease-in-out;
// }
// @keyframes moveLeftRight {
//   0%, 100% { transform: translateX(-10px); }
//   50% { transform: translateX(10px); }
// }
// @keyframes moveRightLeft {
//   0%, 100% { transform: translateX(10px); }
//   50% { transform: translateX(-10px); }
// }

const Home = () => {
  const navigate = useNavigate();

  return (
    <div className="background-gradient h-screen flex flex-col justify-center items-center text-center relative">
      {/* 🏮 โคมไฟขยับซ้ายขวาด้วย CSS animation */}
      <div className="lantern-container absolute top-0 left-1/2 transform -translate-x-1/2 flex gap-8">
        {[...Array(5)].map((_, index) => (
          <div
            key={index}
            className={`lantern ${index % 2 === 0 ? 'lantern-animation-1' : 'lantern-animation-2'}`}
            style={{
              backgroundImage: `url('/light14.svg')`, // ใช้ภาพ SVG
              backgroundSize: "contain",
              backgroundRepeat: "no-repeat",
              width: "80px", // ปรับขนาดโคมไฟ
              height: "120px",
            }}
          />
        ))}
      </div>

      {/* 📌 เนื้อหาหน้า Home */}
      <div className="home-container mt-24">
        <h1 className="text-5xl font-bold text-pink-600 mb-4 font-Phudu">
          Capturing | Booth
        </h1>
        <h4 className="text-lg text-gray-700 mb-6">
          Welcome to Capturing! Photobooth! Lumen & LifeVoyage.
        </h4>
        <img src="/photobooth1.png" alt="photobooth strip" className="photobooth-strip" />
        <button onClick={() => navigate("/welcome")} className="start-button">
          START
        </button>
        <footer className="mt-8 text-sm text-gray-600 text-center font-kanit">
          <p>Version 1.0.3</p>
        </footer>
      </div>
    </div>
  );
};

export default Home;
